import React, { useState, useEffect, useRef } from 'react';
import { CheckCircle, Award, Users, TrendingUp, ChevronLeft, ChevronRight} from 'lucide-react';
import './AboutUsPage.css';

const facilityData = {
  depok: [
    { src: '/facilities/depok1.jpeg', title: 'Robotics Lab', desc: 'Advanced robotics equipment' },
    { src: '/facilities/depok2.jpeg', title: 'AI Lab', desc: 'Machine learning workstation' },
  ],
  kalimalang: [
    { src: '/facilities/j1.jpeg', title: 'IoT Lab', desc: 'Arduino & sensor kit' },
    { src: '/facilities/j2.jpeg', title: 'Electronics Lab', desc: 'PCB & soldering tools' },
  ],
  karawaci: [
    { src: '/facilities/k1.jpeg', title: 'Multimedia Studio', desc: 'Design & editing tools' },
    { src: '/facilities/k2.jpeg', title: '3D Printing', desc: 'Rapid prototyping lab' },
  ],
};

const facilityList = [
  'Advanced Robotics Workshop',
  'Multimedia Design Studio',
  'IoT Development Zone',
  '3D Printing Lab',
  'VR/AR Experience Room',
  'Electronics Assembly Area',
];


function FacilitySlider({ slides }) {
  const [current, setCurrent] = useState(0);
  const autoRef = useRef(null);

  const resetAuto = () => {
    clearInterval(autoRef.current);
    autoRef.current = setInterval(() => {
      setCurrent(prev => (prev + 1) % slides.length);
    }, 4000);
  };

  useEffect(() => {
    resetAuto();
    return () => clearInterval(autoRef.current);
  }, []);

  const prev = () => {
    setCurrent(prev => (prev - 1 + slides.length) % slides.length);
    resetAuto();
  };

  const next = () => {
    setCurrent(prev => (prev + 1) % slides.length);
    resetAuto();
  };

  const goTo = (i) => {
    setCurrent(i);
    resetAuto();
  };

  return (
    <div className="facility-slider">
      {/* Main Image */}
      <div className="facility-slider-main">
        {slides.map((slide, i) => (
          <div
            key={i}
            className={`facility-slide ${i === current ? 'active' : ''}`}
          >
            <img src={slide.src} alt={slide.title} />
            <div className="facility-slide-overlay">
              <h4>{slide.title}</h4>
              <p>{slide.desc}</p>
            </div>
          </div>
        ))}

        {/* Nav Buttons */}
        <button className="facility-btn facility-btn-prev" onClick={prev}>
          <ChevronLeft size={20} />
        </button>
        <button className="facility-btn facility-btn-next" onClick={next}>
          <ChevronRight size={20} />
        </button>

        {/* Dot Indicators */}
        <div className="facility-dots">
          {slides.map((_, i) => (
            <button
              key={i}
              className={`facility-dot ${i === current ? 'active' : ''}`}
              onClick={() => goTo(i)}
            />
          ))}
        </div>
      </div>

      {/* Thumbnail Strip */}
      <div className="facility-thumbs">
        {slides.map((slide, i) => (
          <button
            key={i}
            className={`facility-thumb ${i === current ? 'active' : ''}`}
            onClick={() => goTo(i)}
          >
            <img src={slide.src} alt={slide.title} />
          </button>
        ))}
      </div>
    </div>
  );
}

